import{_ as d,o as r,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"食品与农业行业专项模板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/food/index.md","filePath":"zh/industry/food/index.md"}'),e={name:"zh/industry/food/index.md"};function n(s,t,l,i,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="食品与农业行业专项模板" tabindex="-1">食品与农业行业专项模板 <a class="header-anchor" href="#食品与农业行业专项模板" aria-label="Permalink to &quot;食品与农业行业专项模板&quot;">​</a></h1><blockquote><p><strong>行业背景：</strong> 食品供应链从农场到零售终端，层级多、溯源难，风险涵盖食品安全（FSMA/ISO 22000）、农业劳工（季节性用工、儿童劳动）、用水与土地冲突，以及2023年起生效的《欧盟毁林法规》（EUDR）对大豆、棕榈油、可可等商品的溯源要求。</p></blockquote><h2 id="本节工具" tabindex="-1">本节工具 <a class="header-anchor" href="#本节工具" aria-label="Permalink to &quot;本节工具&quot;">​</a></h2><ul><li><a href="./saq.html">食品农业行业供应商自评问卷（SAQ-FOOD）</a></li><li><a href="./audit-checklist.html">食品行业审核前文件请求清单</a></li></ul><hr><h2 id="行业风险优先级矩阵" tabindex="-1">行业风险优先级矩阵 <a class="header-anchor" href="#行业风险优先级矩阵" aria-label="Permalink to &quot;行业风险优先级矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险类别</th><th>风险等级</th><th>核心指标</th></tr></thead><tbody><tr><td>食品安全 / 掺假</td><td>🔴 极高</td><td>HACCP认证、召回历史</td></tr><tr><td>农业劳工（儿童/强迫）</td><td>🔴 极高</td><td>季节性用工、招募费</td></tr><tr><td>EUDR合规（毁林）</td><td>🔴 极高（欧洲市场）</td><td>农场GPS坐标、土地权属</td></tr><tr><td><strong>动物福利</strong></td><td>🔴 极高（畜牧/水产/乳品）</td><td>五大自由、禁用笼养/强制填饲、OIE人道屠宰</td></tr><tr><td>用水管理</td><td>🟠 高</td><td>水资源压力地区的用水许可</td></tr><tr><td><strong>生物多样性/KBA</strong></td><td>🟠 高</td><td>设施是否位于KBA或保护区缓冲区</td></tr><tr><td>农药残留</td><td>🟠 高</td><td>超标历史、检测频率</td></tr><tr><td>土地冲突/FPIC</td><td>🟠 高</td><td>原住民权利、社区申诉机制</td></tr><tr><td>冷链与物流安全</td><td>🟡 中</td><td>温度记录、防篡改</td></tr><tr><td>包装材料合规</td><td>🟡 中</td><td>食品接触材料法规</td></tr></tbody></table><hr><h2 id="关键法规参照" tabindex="-1">关键法规参照 <a class="header-anchor" href="#关键法规参照" aria-label="Permalink to &quot;关键法规参照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>法规 / 标准</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>FSMA（美国食品安全现代化法）</strong></td><td>对美出口食品</td></tr><tr><td><strong>ISO 22000 / FSSC 22000</strong></td><td>食品安全管理体系</td></tr><tr><td><strong>BRCGS Food</strong></td><td>英国/欧洲零售商</td></tr><tr><td><strong>IFS Food</strong></td><td>欧洲零售商</td></tr><tr><td><strong>GlobalG.A.P.</strong></td><td>农业良好操作规范</td></tr><tr><td><strong>Rainforest Alliance / UTZ</strong></td><td>可持续农业认证</td></tr><tr><td><strong>EUDR（欧盟毁林法规）</strong></td><td>2024年起，大豆/棕榈油/可可/咖啡/牛肉/木材/橡胶</td></tr><tr><td><strong>Fairtrade</strong></td><td>公平贸易认证</td></tr><tr><td><strong>《中华人民共和国食品安全法》</strong></td><td>中国境内生产/销售</td></tr></tbody></table><hr><h2 id="参考案例" tabindex="-1">参考案例 <a class="header-anchor" href="#参考案例" aria-label="Permalink to &quot;参考案例&quot;">​</a></h2><ul><li>马来西亚棕榈油强迫劳动调查（2020–2021）</li><li>雀巢可可供应链儿童劳动诉讼（科特迪瓦）</li><li>中国&quot;瘦肉精&quot;猪肉事件（供应链食品安全掺假）</li></ul>',13)])])}const b=d(e,[["render",n]]);export{g as __pageData,b as default};
